// SYNOPSIS:
//   Computes drift across P0 tenant-configuration streams.
//
//   One row per (StreamName, EntityId, FieldName) that changed between the
//   previous and current observation windows. Used by workbooks and analytic
//   rules to surface configuration changes.
//
// PARAMETERS:
//   lookback - ISO 8601 duration, default 7d. How far back to look for the "previous" snapshot.
//   window   - ISO 8601 duration, default 1h. How recent counts as "current".
//
// INVOCATION:
//   MDE_Drift_P0Compliance(7d, 1h) | where StreamName == "MDE_AdvancedFeatures_CL"
//   MDE_Drift_P0Compliance()       // applies defaults
//
// NOTES:
//   - Parameterized as a KQL function so workbooks/rules can plumb
//     {TimeRange:value} from the time-picker without forking the parser body.
//   - Returns an empty result if no drift.
//   - Drift is computed over the per-stream typed columns (DCR-projected at
//     ingest); RawJson is preserved on each table as a fallback for fields
//     not in the manifest's ProjectionMap, but the parser never re-parses it.
//   - Removed-stream history lives in docs/STREAMS-REMOVED.md + CHANGELOG.md.

let MDE_Drift_P0Compliance = (lookback:timespan = 7d, window:timespan = 1h) {
    // Metadata + envelope columns to exclude from field-level diff (these are
    // bookkeeping; only typed data columns from the manifest ProjectionMap
    // count as "fields" for drift detection).
    let metaCols = dynamic(['TimeGenerated', 'SourceStream', 'EntityId', 'RawJson', '_Table', 'Type', 'TenantId']);
    let sources = union withsource=_Table
        MDE_AdvancedFeatures_CL,
        MDE_PUAConfig_CL,
        MDE_AntivirusPolicy_CL,
        MDE_DeviceControlPolicy_CL,
        MDE_WebContentFiltering_CL,
        MDE_SmartScreenConfig_CL,
        MDE_TenantAllowBlock_CL,
        MDE_CustomCollection_CL,
        MDE_LiveResponseConfig_CL,
        MDE_AlertServiceConfig_CL,
        MDE_AlertTuning_CL,
        MDE_SuppressionRules_CL,
        MDE_CustomDetections_CL,
        MDE_AuthenticatedTelemetry_CL,
        MDE_PreviewFeatures_CL
        | where TimeGenerated > ago(lookback);
    let current = sources
        | where TimeGenerated > ago(window)
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    let previous = sources
        | where TimeGenerated between (ago(lookback) .. ago(window))
        | summarize arg_max(TimeGenerated, *) by _Table, EntityId
        | extend TypedBag = bag_remove_keys(pack_all(), metaCols);
    current
    | join kind=leftouter previous on _Table, EntityId
    | where hash(tostring(TypedBag)) != hash(tostring(TypedBag1)) or isnull(TypedBag1)
    | extend CurrentFields  = bag_keys(TypedBag)
    | extend PreviousFields = iff(isnull(TypedBag1), dynamic([]), bag_keys(TypedBag1))
    | mv-apply field = set_union(CurrentFields, PreviousFields) to typeof(string) on (
        extend
            NewValue = tostring(TypedBag[tostring(field)]),
            OldValue = tostring(iff(isnull(TypedBag1), '', TypedBag1[tostring(field)]))
        | where NewValue != OldValue
      )
    | project
        TimeGenerated,
        StreamName       = _Table,
        EntityId,
        FieldName        = tostring(field),
        OldValue,
        NewValue,
        SnapshotCurrent  = TimeGenerated,
        SnapshotPrevious = TimeGenerated1,
        ChangeType       = iff(isnull(TypedBag1), "Added", iff(isnull(TypedBag[tostring(field)]), "Removed", "Modified"))
};
MDE_Drift_P0Compliance

